#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return (x > y) - (x < y);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        qsort(arr, N, sizeof(int), cmp);
        for (int i = 0; i < M; ++i) {
            int h; scanf("%d", &h);
            int *found = (int*)bsearch(&h, arr, N, sizeof(int), cmp);
            if (i) printf(" ");
            printf(found ? "Yes" : "No");
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

