#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        q_set = {int(next(it)) for _ in range(N)}
        answers = []
        for _ in range(M):
            h = int(next(it))
            answers.append('Yes' if h in q_set else 'No')
        out_lines.append(' '.join(answers))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

